# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
import os

def create_connection():
    connection = mysql.connector.connect(
        host=input("Enter MySQL host (default: localhost): ") or "localhost",
        user=input("Enter MySQL user: "),
        password=input("Enter MySQL password: "),
        database=input("Enter database name: "),
        allow_local_infile=True
    )
    return connection

def bulk_import_data(connection, file_path, table_name, fields_terminated_by=',', 
                     lines_terminated_by='\n', ignore_lines=1, columns=None):
    
    if not os.path.exists(file_path):
        print(f"Error: File {file_path} does not exist")
        return False
    
    cursor = connection.cursor()
    
    file_path = file_path.replace('\\', '/')
    
    load_query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {}".format(file_path, table_name)
    load_query += " FIELDS TERMINATED BY '{}'".format(fields_terminated_by)
    load_query += " LINES TERMINATED BY '{}'".format(lines_terminated_by)
    load_query += " IGNORE {} LINES".format(ignore_lines)
    
    if columns:
        load_query += " ({})".format(', '.join(columns))
    
    try:
        cursor.execute(load_query)
        connection.commit()
        print(f"Successfully imported {cursor.rowcount} rows from {file_path} into {table_name}")
        return True
    except mysql.connector.Error as err:
        print(f"Error importing data: {err}")
        connection.rollback()
        return False
    finally:
        cursor.close()

def import_csv_file(connection):
    file_path = input("Enter the full path to the CSV file: ")
    table_name = input("Enter the target table name: ")
    
    fields_terminated = input("Enter field delimiter (default: ,): ") or ','
    lines_terminated = input("Enter line delimiter (default: \\n): ") or '\n'
    ignore_lines = int(input("Enter number of lines to ignore (default: 1): ") or 1)
    
    columns_input = input("Enter column names (comma-separated, or press Enter to skip): ")
    columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
    
    bulk_import_data(connection, file_path, table_name, fields_terminated, 
                     lines_terminated, ignore_lines, columns)

def import_multiple_files(connection):
    num_files = int(input("Enter number of files to import: "))
    
    for i in range(num_files):
        print(f"\nFile {i+1} of {num_files}:")
        file_path = input("Enter the full path to the file: ")
        table_name = input("Enter the target table name: ")
        
        fields_terminated = input("Enter field delimiter (default: ,): ") or ','
        lines_terminated = input("Enter line delimiter (default: \\n): ") or '\n'
        ignore_lines = int(input("Enter number of lines to ignore (default: 1): ") or 1)
        
        columns_input = input("Enter column names (comma-separated, or press Enter to skip): ")
        columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
        
        bulk_import_data(connection, file_path, table_name, fields_terminated, 
                         lines_terminated, ignore_lines, columns)

def batch_import_from_directory(connection):
    directory_path = input("Enter directory path containing CSV files: ")
    table_name = input("Enter the target table name: ")
    file_pattern = input("Enter file pattern (e.g., *.csv or leave blank for all files): ") or '*'
    
    fields_terminated = input("Enter field delimiter (default: ,): ") or ','
    lines_terminated = input("Enter line delimiter (default: \\n): ") or '\n'
    ignore_lines = int(input("Enter number of lines to ignore (default: 1): ") or 1)
    
    columns_input = input("Enter column names (comma-separated, or press Enter to skip): ")
    columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
    
    if not os.path.exists(directory_path):
        print(f"Error: Directory {directory_path} does not exist")
        return
    
    files = []
    if file_pattern == '*':
        files = [f for f in os.listdir(directory_path) if os.path.isfile(os.path.join(directory_path, f))]
    else:
        import fnmatch
        for f in os.listdir(directory_path):
            if fnmatch.fnmatch(f, file_pattern) and os.path.isfile(os.path.join(directory_path, f)):
                files.append(f)
    
    if not files:
        print("No files found matching the pattern")
        return
    
    print(f"\nFound {len(files)} files to import")
    for file_name in files:
        file_path = os.path.join(directory_path, file_name)
        print(f"\nImporting {file_name}...")
        bulk_import_data(connection, file_path, table_name, fields_terminated, 
                         lines_terminated, ignore_lines, columns)

def custom_load_query(connection):
    file_path = input("Enter the full path to the file: ")
    
    print("\nEnter your custom LOAD DATA INFILE query:")
    print("Example: LOAD DATA LOCAL INFILE '{}' INTO TABLE mytable FIELDS TERMINATED BY ',' LINES TERMINATED BY '\\n' IGNORE 1 LINES".format(file_path))
    
    custom_query = input("\nQuery: ")
    
    if not os.path.exists(file_path):
        print(f"Error: File {file_path} does not exist")
        return
    
    cursor = connection.cursor()
    
    try:
        cursor.execute(custom_query)
        connection.commit()
        print(f"Successfully executed query. Rows affected: {cursor.rowcount}")
    except mysql.connector.Error as err:
        print(f"Error executing query: {err}")
        connection.rollback()
    finally:
        cursor.close()

def main():
    print("=== MySQL Bulk Data Import Tool ===")
    print("Ensure local_infile is enabled in MySQL configuration")
    
    try:
        conn = create_connection()
        print("\nConnection successful!")
        
        while True:
            print("\n--- Import Options ---")
            print("1. Import single CSV file")
            print("2. Import multiple files")
            print("3. Batch import from directory")
            print("4. Execute custom LOAD DATA INFILE query")
            print("5. Exit")
            
            choice = input("\nSelect an option (1-5): ")
            
            if choice == '1':
                import_csv_file(conn)
            elif choice == '2':
                import_multiple_files(conn)
            elif choice == '3':
                batch_import_from_directory(conn)
            elif choice == '4':
                custom_load_query(conn)
            elif choice == '5':
                print("Closing connection and exiting...")
                break
            else:
                print("Invalid option. Please try again.")
        
        conn.close()
        
    except mysql.connector.Error as err:
        print(f"Database connection error: {err}")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()